
.world-panel {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.world-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 5px;
}

.world-stat {
  background: var(--bg-card);
  padding: 5px 7px;
  display: flex;
  flex-direction: column;
}

.world-label {
  font-size: 9px;
  color: var(--text-dim);
  text-transform: uppercase;
}

.world-value {
  font-size: 11px;
  color: var(--text-primary);
  margin-top: 2px;
}

.people-list {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.people-card {
  background: var(--bg-deep);
  border: 1px solid var(--border-dim);
  padding: 4px 7px;
  display: flex;
  gap: 8px;
  align-items: baseline;
}

.people-name {
  font-size: 10px;
  color: var(--gold);
  white-space: nowrap;
}

.people-desc {
  font-size: 10px;
  color: var(--text-secondary);
  line-height: 1.35;
}
