
.sense-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
}

.sense-card {
  background: rgba(0, 0, 0, 0.15);
  border: 1px solid var(--border-dim);
  padding: 7px;
  transition: border-color 0.3s;

  &:hover {
    border-color: var(--border-gold);
  }

  &:first-child {
    grid-column: 1 / -1;
  }
}

.sense-head {
  display: flex;
  align-items: center;
  gap: 5px;
  margin-bottom: 3px;
}

.sense-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  flex-shrink: 0;

  &.整体 { background: var(--gold); box-shadow: 0 0 4px rgba(201, 160, 78, 0.5); }
  &.乳房 { background: #f59e0b; box-shadow: 0 0 4px rgba(245, 158, 11, 0.4); }
  &.臀部 { background: #eab308; box-shadow: 0 0 4px rgba(234, 179, 8, 0.4); }
  &.股间 { background: #ef4444; box-shadow: 0 0 4px rgba(239, 68, 68, 0.4); }
  &.面部 { background: #60a5fa; box-shadow: 0 0 4px rgba(96, 165, 250, 0.4); }
}

.sense-name {
  font-size: 10px;
  color: var(--gold);
  flex-shrink: 0;
}

.sense-bar {
  flex: 1;
  height: 3px;
  background: rgba(255, 255, 255, 0.04);
  overflow: hidden;
}

.sense-bar-fill {
  display: block;
  height: 100%;
  background: linear-gradient(90deg, #d97706, #f59e0b, #eab308);
  transition: width 0.5s ease;
}

.sense-desc {
  font-size: 11px;
  color: var(--text-primary);
  line-height: 1.45;
  padding-left: 11px;
}
