
.header-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  background: rgba(0, 0, 0, 0.2);
  backdrop-filter: blur(4px);
}

.stage-section {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;
  min-width: 0;
}

.stage-ring {
  width: 60px;
  height: 60px;
  position: relative;
  flex-shrink: 0;

  svg {
    width: 100%;
    height: 100%;
    transform: rotate(-90deg);
  }

  .ring-bg {
    fill: none;
    stroke: rgba(255, 255, 255, 0.04);
    stroke-width: 3;
  }

  .ring-fill {
    fill: none;
    stroke-width: 3;
    stroke-linecap: round;
    transition: stroke-dashoffset 0.5s ease;
  }
}

.ring-early .ring-fill {
  stroke: #a78bfa;
  filter: drop-shadow(0 0 4px rgba(167, 139, 250, 0.4));
  stroke-dasharray: 163.36;
}
.ring-mid .ring-fill {
  stroke: #f87171;
  filter: drop-shadow(0 0 4px rgba(248, 113, 113, 0.4));
  stroke-dasharray: 163.36;
}
.ring-late .ring-fill {
  stroke: var(--gold);
  filter: drop-shadow(0 0 4px rgba(201, 160, 78, 0.4));
  stroke-dasharray: 163.36;
}
.ring-final .ring-fill {
  stroke: var(--crimson-light);
  filter: drop-shadow(0 0 6px rgba(201, 51, 90, 0.6));
  stroke-dasharray: 163.36;
}

.ring-inner {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.ring-value {
  font-size: 16px;
  font-weight: bold;
  color: var(--text-primary);
}

.stage-info {
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.stage-title {
  font-size: 14px;
  font-weight: bold;
  white-space: nowrap;

  &.ring-early { color: #a78bfa; text-shadow: 0 0 6px rgba(167, 139, 250, 0.3); }
  &.ring-mid { color: #f87171; text-shadow: 0 0 6px rgba(248, 113, 113, 0.3); }
  &.ring-late { color: var(--gold); text-shadow: 0 0 6px rgba(201, 160, 78, 0.3); }
  &.ring-final { color: var(--crimson-light); text-shadow: 0 0 8px rgba(201, 51, 90, 0.5); animation: pulse-final 2s ease-in-out infinite; }
}

@keyframes pulse-final {
  0%, 100% { text-shadow: 0 0 8px rgba(201, 51, 90, 0.4); }
  50% { text-shadow: 0 0 16px rgba(201, 51, 90, 0.8); }
}

.stage-sub {
  font-size: 9px;
  color: var(--text-dim);
  text-transform: uppercase;
  letter-spacing: 1px;
}

.dev-section {
  flex-shrink: 0;
}

.mini-gauge {
  width: 40px;
  height: 40px;
  position: relative;

  svg {
    width: 100%;
    height: 100%;
    transform: rotate(-90deg);
  }

  .gauge-bg {
    fill: none;
    stroke: rgba(255, 255, 255, 0.04);
    stroke-width: 2.5;
  }

  .gauge-fill {
    fill: none;
    stroke-width: 2.5;
    stroke-linecap: round;
    transition: stroke-dashoffset 0.5s ease;

    &.dev {
      stroke: #f59e0b;
      filter: drop-shadow(0 0 3px rgba(245, 158, 11, 0.4));
      stroke-dasharray: 100.53;
    }
  }

  .gauge-label {
    position: absolute;
    inset: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
  }

  .gauge-value {
    font-size: 11px;
    font-weight: bold;
    color: var(--text-primary);
    line-height: 1;
  }

  .gauge-sub {
    font-size: 7px;
    color: var(--text-dim);
    text-transform: uppercase;
  }
}

.toggle-btn {
  padding: 6px 8px;
  border: 1px solid var(--border-dim);
  background: rgba(255, 255, 255, 0.02);
  color: var(--text-dim);
  font-family: inherit;
  font-size: 10px;
  cursor: pointer;
  white-space: nowrap;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  transition: all 0.2s;

  &:hover {
    color: var(--gold);
    border-color: var(--border-gold);
    background: rgba(201, 160, 78, 0.06);
  }
}

.toggle-icon {
  font-size: 10px;
  line-height: 1;
}

.toggle-text {
  font-size: 8px;
  text-transform: uppercase;
  letter-spacing: 1px;
}
